          kind: String(k),
          color: String(color),
          style: String(style),
          width: Number.isFinite(widthResolved) ? widthResolved : null,
          dash: dashMeta && dashMeta.dash ? String(dashMeta.dash) : null,
          hasSvgPreview: (k === 'style') ? !!hasSvgPreview : null,
          viaSvg: (k === 'style') ? !!svgApplied : null,
