          menuEl.style.display = 'block';
          menuEl.style.position = 'fixed';
          menuEl.style.left = '-10000px';
          menuEl.style.top = '-10000px';
          menuEl.style.right = 'auto';
          menuEl.style.bottom = 'auto';
