          let stateUpdate = null;
          try {
            stateUpdate = _lmUpdateStateDataBorderInfo(sheet, nextBorderInfo);
          } catch (_) {
            stateUpdate = { ok: false, why: 'state-update-error' };
          }

          // If setData exists, prefer it to ensure vendor re-renders from updated model.
          let setDataResult = null;
          try {
            setDataResult = _lmTrySetDataBorderInfo(sheet, nextBorderInfo);
          } catch (_) {}

