    const labelHpx = Math.max(0, Math.round(layoutVars.labelHpx || 0));
    const rowHeaderW = Math.max(0, Math.round(layoutVars.rowHeaderW || 0)) || 45;
    const colHeaderH = Math.max(0, Math.round(layoutVars.colHeaderH || 0)) || 18;
