  const getCellTextCache = (sheet, r, c) => {
    try {
      if (!sheet || !Number.isFinite(r) || !Number.isFinite(c)) return null;
      const key = makeCellCacheKey(sheet, r, c);
      return cellTextCache.get(key) || null;
    } catch (_) {
      return null;
    }
  };
