      if (!wrapper) return;
      wrapper.style.left = `${Math.round(toFiniteNumber(barcode.left, 0))}px`;
      wrapper.style.top = `${Math.round(toFiniteNumber(barcode.top, 0))}px`;
      if (barcode.width != null && toFiniteNumber(barcode.width, 0) > 0) {
        wrapper.style.width = `${Math.round(toFiniteNumber(barcode.width, 0))}px`;
      }
