      if (a) {
        const tag = a.tagName ? String(a.tagName).toLowerCase() : '';
        const isForm = tag === 'input' || tag === 'textarea' || tag === 'select';
        if (isForm || a.isContentEditable) {
          try { a.blur(); } catch (_) {}
        }
      }
