          scale: Number(opts.scale || base.scale || 3),
          height: Number(opts.height || base.height || 10),
          includetext: opts.includetext != null ? Boolean(opts.includetext) : Boolean(base.includetext || false),
          rotate: Number.isFinite(nextRotate) ? nextRotate : base.rotate,
