            span.style.setProperty('width', '0', 'important');
            span.style.setProperty('overflow', 'hidden', 'important');
            span.style.setProperty('font-size', '0', 'important');
            span.style.setProperty('line-height', '0', 'important');
            span.style.setProperty('letter-spacing', '0', 'important');
            span.style.setProperty('padding', '0', 'important');
            span.style.setProperty('margin', '0', 'important');
            span.style.setProperty('border', '0', 'important');
            span.style.setProperty('user-select', 'none', 'important');
