                const hasMarkerSpans = !!editor.querySelector('span.fs-ss-marker, span.fs-lm-marker');
                const runCount = editor.querySelectorAll ? editor.querySelectorAll('span.fs-lm-run').length : 0;
                let allowRewrap = hasMarkerSpans && runCount === 0;
